// Rise 6.0 - AutoRespawn (triggered by S06 health ≤ 0):
@EventLink()
public final Listener<PacketReceiveEvent> onPacketReceive = event -> {
    if (event.getPacket() instanceof S06PacketUpdateHealth) {
        S06PacketUpdateHealth s06 = (S06PacketUpdateHealth) event.getPacket();
        if (mc.thePlayer != null && s06.getHealth() <= 0.0f) {
            mc.thePlayer.sendQueue.addToSendQueue(
                new C16PacketClientStatus(
                    C16PacketClientStatus.EnumState.PERFORM_RESPAWN));
            mc.thePlayer.setHealth(20.0f);
        }
    }
};

// Vanilla S06PacketUpdateHealth definition:
package net.minecraft.network.play.server;

import net.minecraft.network.Packet;
import net.minecraft.network.PacketBuffer;
import net.minecraft.network.play.INetHandlerPlayClient;
import java.io.IOException;

public class S06PacketUpdateHealth implements Packet<INetHandlerPlayClient> {
    private float health;
    private int foodLevel;
    private float saturationLevel;

    public S06PacketUpdateHealth() {}
    public S06PacketUpdateHealth(float healthIn, int foodLevelIn, float saturationIn) {
        this.health = healthIn;
        this.foodLevel = foodLevelIn;
        this.saturationLevel = saturationIn;
    }

    public void processPacket(INetHandlerPlayClient handler) {
        handler.handleUpdateHealth(this);
    }

    public float getHealth() { return this.health; }
    public int getFoodLevel() { return this.foodLevel; }
    public float getSaturationLevel() { return this.saturationLevel; }
}

// Gugustus - GodMode (prevent death via S06 cancel):
@EventTarget
public void onPacketReceive(EventReceivePacket event) {
    if (event.getPacket() instanceof S06PacketUpdateHealth) {
        S06PacketUpdateHealth s06 = (S06PacketUpdateHealth) event.getPacket();
        if (s06.getHealth() <= 0.0f) {
            // Cancel death packet — client never shows death screen
            event.setCancelled(true);
            // Keep client thinking we're alive
            mc.thePlayer.setHealth(20.0f);
        }
    }
}
